    if response.returncode != 0:
        return jsonify({'error': 'Failed to take screenshot'}), 500
    
    # Save screenshot to S3
    s3 = boto3.client('s3', region_name=S3_REGION)
    try:
        s3.put_object(Bucket=S3_BUCKET_NAME, Key=url.replace('/', '_') + '.png', Body=response.stdout, ContentType='image/png')
    except NoCredentialsError:
        return jsonify({'error': 'Failed to upload screenshot to S3'}), 500
    
    return jsonify({'url': f'https://{S3_BUCKET_NAME}.s3-{S3_REGION}.amazonaws.com/{url.replace("/", "_")}.png'})

